codeExamples.secure:
// SECURE
const name = escapeHtml(req.query.name);
res.send(`<h1>Hello ${name}</h1>`);

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#x27;');
}

